window.WORVOX_SCENARIOS=[{id:1,title:"공항 체크인",category:"여행",difficulty:"beginner",icon:"✈️",description:"항공편 체크인과 수하물 처리",sentences:["I'd like to check in for flight KE123 to New York.","Can I have a window seat, please?","I have two bags to check in.","Is the flight on time?","Where is gate number fifteen?"],translations:["뉴욕행 KE123편으로 체크인하고 싶습니다.","창가 좌석으로 부탁드립니다.","위탁 수하물이 두 개 있습니다.","비행기가 정시에 출발하나요?","15번 게이트가 어디인가요?"]},{id:2,title:"호텔 예약",category:"여행",difficulty:"beginner",icon:"🏨",description:"호텔 룸 예약 및 체크인",sentences:["I have a reservation under the name Smith.","What time is checkout?","Could you call a taxi for me, please?","Does the room have Wi-Fi?","Is breakfast included in the rate?"],translations:["스미스 이름으로 예약했습니다.","체크아웃 시간이 언제인가요?","택시를 불러주시겠어요?","방에 와이파이가 있나요?","조식이 요금에 포함되어 있나요?"]},{id:3,title:"레스토랑 주문",category:"일상",difficulty:"beginner",icon:"🍽️",description:"레스토랑에서 음식 주문하기",sentences:["Can I see the menu, please?","I'll have the grilled salmon with vegetables.","Could I get the bill, please?","What would you recommend?","Is this dish spicy?"],translations:["메뉴판을 볼 수 있을까요?","그릴에 구운 연어와 야채로 주세요.","계산서를 받을 수 있을까요?","추천해주실 만한 게 있나요?","이 요리는 매운가요?"]},{id:4,title:"길 묻기",category:"일상",difficulty:"beginner",icon:"🗺️",description:"길을 잃었을 때 방향 묻기",sentences:["Excuse me, how do I get to the subway station?","Is it walking distance from here?","Should I take a bus or taxi?","Can you show me on the map?","How long does it take to get there?"],translations:["실례합니다, 지하철역에 어떻게 가나요?","여기서 걸어갈 수 있는 거리인가요?","버스나 택시를 타야 하나요?","지도에서 보여주실 수 있나요?","거기까지 얼마나 걸리나요?"]},{id:5,title:"쇼핑하기",category:"일상",difficulty:"beginner",icon:"🛍️",description:"옷가게에서 쇼핑하기",sentences:["Do you have this in a smaller size?","Can I try this on?","Where is the fitting room?","Do you accept credit cards?","Is this on sale?"],translations:["이것보다 작은 사이즈 있나요?","입어봐도 될까요?","탈의실이 어디인가요?","신용카드 받으시나요?","이거 세일 중인가요?"]},{id:6,title:"은행 업무",category:"비즈니스",difficulty:"intermediate",icon:"🏦",description:"은행에서 계좌 개설하기",sentences:["I'd like to open a savings account.","What documents do I need?","What's the interest rate?","Is there a minimum balance requirement?","Can I access my account online?"],translations:["저축 계좌를 개설하고 싶습니다.","어떤 서류가 필요한가요?","이자율이 어떻게 되나요?","최소 잔액 요건이 있나요?","온라인으로 계좌에 접속할 수 있나요?"]},{id:7,title:"병원 방문",category:"일상",difficulty:"intermediate",icon:"🏥",description:"병원에서 진료 받기",sentences:["I have an appointment with Dr. Johnson.","I've been feeling dizzy lately.","Do I need a prescription for this medication?","How often should I take this medicine?","When should I come back for a follow-up?"],translations:["존슨 박사님과 예약이 있습니다.","최근에 어지러움을 느끼고 있습니다.","이 약은 처방전이 필요한가요?","이 약을 얼마나 자주 복용해야 하나요?","언제 다시 와서 진료를 받아야 하나요?"]},{id:8,title:"직장 회의",category:"비즈니스",difficulty:"advanced",icon:"💼",description:"비즈니스 회의 진행하기",sentences:["Let's go over the quarterly results.","I'd like to propose a new marketing strategy.","What's your take on this approach?","We need to allocate more resources to this project.","Can we schedule a follow-up meeting next week?"],translations:["분기별 실적을 검토해 봅시다.","새로운 마케팅 전략을 제안하고 싶습니다.","이 접근 방식에 대해 어떻게 생각하시나요?","이 프로젝트에 더 많은 자원을 할당해야 합니다.","다음 주에 후속 회의를 잡을 수 있을까요?"]},{id:9,title:"면접 준비",category:"비즈니스",difficulty:"advanced",icon:"👔",description:"취업 면접 대비하기",sentences:["Tell me about your previous work experience.","What are your strengths and weaknesses?","Why do you want to work for our company?","Where do you see yourself in five years?","Do you have any questions for us?"],translations:["이전 업무 경험에 대해 말씀해 주세요.","당신의 강점과 약점은 무엇인가요?","왜 우리 회사에서 일하고 싶으신가요?","5년 후 자신의 모습을 어떻게 그리고 계신가요?","저희에게 질문 있으신가요?"]},{id:10,title:"전화 통화",category:"비즈니스",difficulty:"intermediate",icon:"📞",description:"비즈니스 전화 응대하기",sentences:["May I speak to Mr. Park, please?","Could you hold on for a moment?","I'm calling regarding the contract we discussed.","Can I leave a message?","When would be a good time to call back?"],translations:["박 과장님과 통화할 수 있을까요?","잠시만 기다려 주시겠어요?","우리가 논의한 계약 건에 대해 전화드렸습니다.","메시지를 남길 수 있을까요?","언제 다시 전화드리면 좋을까요?"]}],console.log("✅ WorVox Scenarios loaded:",window.WORVOX_SCENARIOS.length,"scenarios");